// entry: src/index.ts
import { OpenAI } from "openai";        // from node_modules
import { chatHandler } from "./chat";    // local file

// You import only `chat.completions.create` from the OpenAI SDK
// Tree shaking removes the audio, images, and fine-tuning modules
// that you never imported

// tsconfig.json — minimal for a Node.js AI backend
{
  "compilerOptions": {
    "target": "ES2022",
    "module": "NodeNext",
    "moduleResolution": "NodeNext",
    "strict": true,
    "outDir": "dist",
    "sourceMap": true
  },
  "include": ["src"]
}

// vite.config.ts
import { defineConfig } from "vite";
import react from "@vitejs/plugin-react";

export default defineConfig({
  plugins: [react()],
  define: {
    // Expose only public env vars to the browser bundle
    // Never put API keys here — use a backend proxy instead
    "import.meta.env.VITE_APP_TITLE": JSON.stringify(process.env.VITE_APP_TITLE),
  },
});

// package.json scripts for a Gen AI app
{
  "scripts": {
    "dev": "vite",
    "build": "tsc --noEmit && vite build",
    "typecheck": "tsc --noEmit",
    "start": "node dist/server.js"
  }
}

// This is safe — runs on the server only (API route or Server Action)
const openai = new OpenAI({ apiKey: process.env.OPENAI_API_KEY });

// This would be dangerous — never do this in a Client Component
const openai = new OpenAI({ apiKey: process.env.NEXT_PUBLIC_OPENAI_API_KEY });

import OpenAI from "openai";

// Instantiated once; reused across requests in the same runtime instance
export const openai = new OpenAI({
  apiKey: process.env.OPENAI_API_KEY, // Server-only env var — safe
});

import { openai } from "@/lib/openai";
import { OpenAIStream, StreamingTextResponse } from "ai"; // Vercel AI SDK

export const runtime = "nodejs"; // or "edge" for Cloudflare-compatible edge

export async function POST(req: Request) {
  const { messages } = await req.json();

  const response = await openai.chat.completions.create({
    model: "gpt-4o",
    messages,
    stream: true,
  });

  const stream = OpenAIStream(response);
  return new StreamingTextResponse(stream);
}

import type { NextConfig } from "next";

const config: NextConfig = {
  experimental: {
    turbo: {}, // Opt in to Turbopack in Next.js 15
  },
};

export default config;

// Breaks with isolatedModules
export { SomeType } from "./types";

// Correct
export type { SomeType } from "./types";

// Less efficient — may import more than needed
import * as anthropic from "@anthropic-ai/sdk";

// Better — bundler can tree-shake unused exports
import Anthropic from "@anthropic-ai/sdk";
